87	// === STRATEGY: Concentrated single-wall strip ===
88	// Build one full-width wall (30 cells) along one edge of the grid,
89	// creating a large pet-free strip. ALL humans cooperate on this single wall.
90	// The strip uses 3 grid boundaries + 1 built wall.
91	//
92	// Additionally, compare against L-shaped corner pairs as fallback.
93	
94	struct StripPlan {
95	    int edge; // 0=top, 1=bottom, 2=left, 3=right
96	    int wall_pos; // row or col of the wall
97	    int depth; // depth of the safe strip (# rows or cols)
98	    int area;
99	    int pets_inside;
100	    double score;
101	    // Safe zone boundaries
102	    int r_min, r_max, c_min, c_max;
103	};
104	
105	struct CornerPlan {
106	    int corner; // 0=TL, 1=TR, 2=BL, 3=BR
107	    int wall_row, wall_col;
108	    int area, cost, pets_inside;
109	    double score;
110	    int r_min, r_max, c_min, c_max;
111	};
112	
113	std::vector<Point> get_strip_wall_cells(const StripPlan& plan) {
114	    std::vector<Point> cells;
115	    if (plan.edge == 0) { // top: horizontal wall at wall_pos
116	        for (int c = 1; c <= GRID_SIZE; c++) cells.push_back({plan.wall_pos, c});
117	    } else if (plan.edge == 1) { // bottom: horizontal wall at wall_pos
118	        for (int c = 1; c <= GRID_SIZE; c++) cells.push_back({plan.wall_pos, c});
119	    } else if (plan.edge == 2) { // left: vertical wall at wall_pos
120	        for (int r = 1; r <= GRID_SIZE; r++) cells.push_back({r, plan.wall_pos});
121	    } else { // right: vertical wall at wall_pos
122	        for (int r = 1; r <= GRID_SIZE; r++) cells.push_back({r, plan.wall_pos});
123	    }
124	    return cells;
125	}
126	
127	std::vector<Point> get_corner_wall_cells(const CornerPlan& plan) {
128	    std::vector<Point> cells;
129	    if (plan.corner == 0) {
130	        for (int c = 1; c <= plan.wall_col; c++) cells.push_back({plan.wall_row, c});
131	        for (int r = 1; r < plan.wall_row; r++) cells.push_back({r, plan.wall_col});
132	    } else if (plan.corner == 1) {
133	        for (int c = plan.wall_col; c <= GRID_SIZE; c++) cells.push_back({plan.wall_row, c});
134	        for (int r = 1; r < plan.wall_row; r++) cells.push_back({r, plan.wall_col});
135	    } else if (plan.corner == 2) {
136	        for (int c = 1; c <= plan.wall_col; c++) cells.push_back({plan.wall_row, c});
137	        for (int r = plan.wall_row + 1; r <= GRID_SIZE; r++) cells.push_back({r, plan.wall_col});
138	    } else {
139	        for (int c = plan.wall_col; c <= GRID_SIZE; c++) cells.push_back({plan.wall_row, c});
140	        for (int r = plan.wall_row + 1; r <= GRID_SIZE; r++) cells.push_back({r, plan.wall_col});
141	    }
142	    return cells;
143	}
