154	void find_best_strip(StripPlan& best) {
155	    best.score = -1;
156	
157	    for (int edge = 0; edge < 4; edge++) {
158	        int max_depth = (edge < 2) ? 14 : 14; // don't go past halfway
159	        for (int depth = 3; depth <= max_depth; depth++) {
160	            StripPlan sp;
161	            sp.edge = edge;
162	            sp.depth = depth;
163	
164	            if (edge == 0) { // top strip: rows 1..depth, wall at row depth+1
165	                sp.wall_pos = depth + 1;
166	                sp.r_min = 1; sp.r_max = depth;
167	                sp.c_min = 1; sp.c_max = GRID_SIZE;
168	            } else if (edge == 1) { // bottom strip: rows (30-depth+1)..30, wall at row (30-depth)
169	                sp.wall_pos = GRID_SIZE - depth;
170	                sp.r_min = GRID_SIZE - depth + 1; sp.r_max = GRID_SIZE;
171	                sp.c_min = 1; sp.c_max = GRID_SIZE;
172	            } else if (edge == 2) { // left strip: cols 1..depth, wall at col depth+1
173	                sp.wall_pos = depth + 1;
174	                sp.r_min = 1; sp.r_max = GRID_SIZE;
175	                sp.c_min = 1; sp.c_max = depth;
176	            } else { // right strip: cols (30-depth+1)..30, wall at col (30-depth)
177	                sp.wall_pos = GRID_SIZE - depth;
178	                sp.r_min = 1; sp.r_max = GRID_SIZE;
179	                sp.c_min = GRID_SIZE - depth + 1; sp.c_max = GRID_SIZE;
180	            }
181	
182	            sp.area = (sp.r_max - sp.r_min + 1) * (sp.c_max - sp.c_min + 1);
183	            sp.pets_inside = 0;
184	
185	            for (auto& p : pets) {
186	                if (p.r >= sp.r_min && p.r <= sp.r_max && p.c >= sp.c_min && p.c <= sp.c_max) {
187	                    sp.pets_inside++;
188	                }
189	            }
190	
191	            // Also count pets adjacent to the wall (they'll block construction)
192	            int pets_near_wall = 0;
193	            if (edge < 2) {
194	                for (auto& p : pets) {
195	                    if (std::abs(p.r - sp.wall_pos) <= 1 && p.c >= 1 && p.c <= GRID_SIZE)
196	                        pets_near_wall++;
197	                }
198	            } else {
199	                for (auto& p : pets) {
200	                    if (std::abs(p.c - sp.wall_pos) <= 1 && p.r >= 1 && p.r <= GRID_SIZE)
201	                        pets_near_wall++;
202	                }
203	            }
204	
205	            // Score: area/900 * 2^(-pets_inside), penalized for construction difficulty
206	            double base_score = (double)sp.area / 900.0 * std::pow(2.0, -(double)sp.pets_inside);
207	
208	            // Strong preference for 0 pets inside
209	            double pet_bonus = (sp.pets_inside == 0) ? 2.5 : (sp.pets_inside == 1) ? 1.0 : 0.3;
210	
211	            // Penalty for pets near wall (they block construction)
212	            double near_penalty = 1.0 / (1.0 + pets_near_wall * 0.3);
213	
214	            // Slight penalty for larger walls (30 cells is fixed cost)
215	            // But reward larger area strongly
216	            double area_bonus = std::sqrt((double)sp.area / 150.0);
217	
218	            sp.score = base_score * pet_bonus * near_penalty * area_bonus;
219	
220	            if (sp.score > best.score) {
221	                best = sp;
222	            }
223	        }
224	    }
225	}
