227	void find_best_corner(int corner_id, CornerPlan& best) {
228	    best.score = -1;
229	    for (int wr = 2; wr <= 29; wr++) {
230	        for (int wc = 2; wc <= 29; wc++) {
231	            int r_min, r_max, c_min, c_max, cost;
232	            if (corner_id == 0) { r_min=1; r_max=wr-1; c_min=1; c_max=wc-1; cost=wc+(wr-1); }
233	            else if (corner_id == 1) { r_min=1; r_max=wr-1; c_min=wc+1; c_max=GRID_SIZE; cost=(GRID_SIZE-wc+1)+(wr-1); }
234	            else if (corner_id == 2) { r_min=wr+1; r_max=GRID_SIZE; c_min=1; c_max=wc-1; cost=wc+(GRID_SIZE-wr); }
235	            else { r_min=wr+1; r_max=GRID_SIZE; c_min=wc+1; c_max=GRID_SIZE; cost=(GRID_SIZE-wc+1)+(GRID_SIZE-wr); }
236	
237	            int area = (r_max - r_min + 1) * (c_max - c_min + 1);
238	            if (area < 50 || cost > 40) continue;
239	
240	            int pets_inside = 0;
241	            for (auto& p : pets) {
242	                if (p.r >= r_min && p.r <= r_max && p.c >= c_min && p.c <= c_max)
243	                    pets_inside++;
244	            }
245	
246	            double base_score = (double)area / 900.0 * std::pow(2.0, -(double)pets_inside);
247	            double time_factor = 1.0 / (1.0 + cost * 0.01);
248	            double pet_bonus = (pets_inside == 0) ? 2.0 : 1.0;
249	            double score = base_score * time_factor * pet_bonus;
250	
251	            if (score > best.score) {
252	                best.corner = corner_id;
253	                best.wall_row = wr; best.wall_col = wc;
254	                best.area = area; best.cost = cost;
255	                best.pets_inside = pets_inside; best.score = score;
256	                best.r_min = r_min; best.r_max = r_max;
257	                best.c_min = c_min; best.c_max = c_max;
258	            }
259	        }
260	    }
261	}
