263	void choose_strategy() {
264	    // Find best strip
265	    StripPlan strip;
266	    find_best_strip(strip);
267	
268	    // Find best corner pair
269	    CornerPlan corners[4];
270	    for (int i = 0; i < 4; i++) find_best_corner(i, corners[i]);
271	
272	    double best_pair_score = -1;
273	    int best_pair[2] = {0, 3};
274	    int pairs[2][2] = {{0, 3}, {1, 2}};
275	    for (auto& pair : pairs) {
276	        double combined = corners[pair[0]].score + corners[pair[1]].score;
277	        if (combined > best_pair_score) {
278	            best_pair_score = combined;
279	            best_pair[0] = pair[0]; best_pair[1] = pair[1];
280	        }
281	    }
282	
283	    // Compare strip vs corner pair
284	    // The strip gets ALL humans in one zone, so effective per-person score is higher
285	    // Corner pair splits humans between two zones
286	    // For strip: all M humans get area/900 (assuming 0 pets)
287	    // For corners: humans split between two smaller areas
288	    double strip_effective = strip.score;
289	    double corner_effective = best_pair_score * 0.5; // halved because split
290	
291	    if (strip_effective > corner_effective && strip.pets_inside <= 1) {
292	        strategy_mode = 0; // strip
293	        best_strip = strip;
294	        wall_cells_to_build = get_strip_wall_cells(strip);
295	    } else {
296	        strategy_mode = 1; // corner pair
297	        num_plans = 2;
298	        plans[0] = corners[best_pair[0]];
299	        plans[1] = corners[best_pair[1]];
300	    }
301	}
