303	// Assign humans to wall sections for strip strategy
304	void assign_strip_sections() {
305	    int total_cells = (int)wall_cells_to_build.size();
306	    int cells_per_human = total_cells / M;
307	    int extra = total_cells % M;
308	
309	    // Sort humans by their position along the wall axis for efficient assignment
310	    std::vector<std::pair<int, int>> human_pos(M); // (position_along_wall, human_idx)
311	    for (int i = 0; i < M; i++) {
312	        if (best_strip.edge < 2) { // horizontal wall
313	            human_pos[i] = {humans[i].c, i};
314	        } else { // vertical wall
315	            human_pos[i] = {humans[i].r, i};
316	        }
317	    }
318	    std::sort(human_pos.begin(), human_pos.end());
319	
320	    int start = 0;
321	    for (int rank = 0; rank < M; rank++) {
322	        int idx = human_pos[rank].second;
323	        int my_count = cells_per_human + (rank < extra ? 1 : 0);
324	        human_wall_section[idx] = start; // start index into wall_cells_to_build
325	        start += my_count;
326	    }
327	}
