333	void assign_humans_corners() {
334	    int count0 = M / 2;
335	    std::vector<std::pair<double, int>> preference(M);
336	    for (int i = 0; i < M; i++) {
337	        double cr0 = (plans[0].r_min + plans[0].r_max) / 2.0;
338	        double cc0 = (plans[0].c_min + plans[0].c_max) / 2.0;
339	        double d0 = std::abs(humans[i].r - cr0) + std::abs(humans[i].c - cc0);
340	        double cr1 = (plans[1].r_min + plans[1].r_max) / 2.0;
341	        double cc1 = (plans[1].c_min + plans[1].c_max) / 2.0;
342	        double d1 = std::abs(humans[i].r - cr1) + std::abs(humans[i].c - cc1);
343	        preference[i] = {d0 - d1, i};
344	    }
345	    std::sort(preference.begin(), preference.end());
346	    int assigned0 = 0;
347	    for (auto& [pref, idx] : preference) {
348	        if (assigned0 < count0) { human_plan_assignment[idx] = 0; assigned0++; }
349	        else { human_plan_assignment[idx] = 1; }
350	    }
351	}
