389	
390	    for (int turn = 0; turn < NUM_TURNS; turn++) {
391	        std::string actions(M, '.');
392	        std::vector<Point> walls_being_built;
393	
394	        if (strategy_mode == 0) {
395	            // Strip strategy: all humans build one wall cooperatively
396	            int total_cells = (int)wall_cells_to_build.size();
397	            int cells_per_human = total_cells / M;
398	            int extra = total_cells % M;
399	
400	            for (int i = 0; i < M; i++) {
401	                // Find my section boundaries
402	                // Recompute based on sorted assignment
403	                int my_start = human_wall_section[i];
404	                int rank_of_i = -1;
405	                // Determine how many cells this human is responsible for
406	                // We need to reconstruct which rank this human has
407	                std::vector<std::pair<int, int>> human_pos(M);
408	                for (int j = 0; j < M; j++) {
409	                    if (best_strip.edge < 2) human_pos[j] = {humans[j].c, j};
410	                    else human_pos[j] = {humans[j].r, j};
411	                }
412	                // Actually just compute section end from start
413	                int my_count = cells_per_human;
414	                // Check if this human gets an extra cell (first 'extra' humans sorted do)
415	                // Simpler: just find the next human's start to determine my end
416	                int my_end = total_cells; // default: goes to end
417	                for (int j = 0; j < M; j++) {
418	                    if (j == i) continue;
419	                    if (human_wall_section[j] > my_start && human_wall_section[j] < my_end) {
420	                        my_end = human_wall_section[j];
421	                    }
422	                }
423	
424	                // Find nearest unbuilt wall cell in my section
425	                int best_idx = -1;
426	                int best_dist = INF;
427	                for (int w = my_start; w < my_end; w++) {
428	                    Point wc = wall_cells_to_build[w];
429	                    if (grid[wc.r][wc.c]) continue;
430	                    bool claimed = false;
431	                    for (auto& wb : walls_being_built) {
432	                        if (wb == wc) { claimed = true; break; }
433	                    }
434	                    if (claimed) continue;
435	                    int dist = std::abs(humans[i].r - wc.r) + std::abs(humans[i].c - wc.c);
436	                    if (dist < best_dist) { best_dist = dist; best_idx = w; }
437	                }
438	
439	                // If my section is done, help with any remaining unbuilt cell
440	                if (best_idx == -1) {
441	                    for (int w = 0; w < total_cells; w++) {
442	                        Point wc = wall_cells_to_build[w];
443	                        if (grid[wc.r][wc.c]) continue;
444	                        bool claimed = false;
445	                        for (auto& wb : walls_being_built) {
446	                            if (wb == wc) { claimed = true; break; }
447	                        }
448	                        if (claimed) continue;
449	                        int dist = std::abs(humans[i].r - wc.r) + std::abs(humans[i].c - wc.c);
450	                        if (dist < best_dist) { best_dist = dist; best_idx = w; }
451	                    }
452	                }
453	
454	                if (best_idx == -1) {
455	                    // All walls built - move to safe zone center
456	                    int tr = (best_strip.r_min + best_strip.r_max) / 2;
457	                    int tc = (best_strip.c_min + best_strip.c_max) / 2;
458	                    Point target = {tr, tc};
459	                    if (!passable(target.r, target.c)) {
460	                        for (int r = best_strip.r_min; r <= best_strip.r_max; r++) {
461	                            for (int c = best_strip.c_min; c <= best_strip.c_max; c++) {
462	                                if (passable(r, c)) { target = {r, c}; goto found_strip_target; }
463	                            }
464	                        }
465	                        found_strip_target:;
466	                    }
467	                    if (humans[i] != target) {
468	                        actions[i] = move_toward(humans[i], target);
469	                    }
470	                } else {
471	                    Point wall_target = wall_cells_to_build[best_idx];
472	
473	                    // Find standing position: prefer safe side
474	                    Point stand_pos = {-1, -1};
475	                    int best_stand_dist = INF;
476	                    for (int d = 0; d < 4; d++) {
477	                        int sr = wall_target.r + DR[d];
478	                        int sc = wall_target.c + DC[d];
479	                        if (!passable(sr, sc)) continue;
480	                        bool in_safe = is_safe_side_strip(sr, sc);
481	                        int dist = std::abs(humans[i].r - sr) + std::abs(humans[i].c - sc);
482	                        int effective_dist = in_safe ? dist : dist + 50;
483	                        if (effective_dist < best_stand_dist) {
484	                            best_stand_dist = effective_dist;
485	                            stand_pos = {sr, sc};
486	                        }
487	                    }
488	
489	                    if (stand_pos.r == -1) {
490	                        for (int d = 0; d < 4; d++) {
491	                            int sr = wall_target.r + DR[d];
492	                            int sc = wall_target.c + DC[d];
493	                            if (passable(sr, sc)) { stand_pos = {sr, sc}; break; }
494	                        }
495	                    }
496	
497	                    if (stand_pos.r == -1) {
498	                        actions[i] = '.';
499	                    } else if (humans[i] == stand_pos) {
500	                        if (can_build_wall(wall_target.r, wall_target.c)) {
501	                            for (int d = 0; d < 4; d++) {
502	                                if (humans[i].r + DR[d] == wall_target.r &&
503	                                    humans[i].c + DC[d] == wall_target.c) {
504	                                    actions[i] = BUILD_CH[d];
505	                                    walls_being_built.push_back(wall_target);
