                    }
                    if (claimed) continue;
                    int dist = std::abs(humans[i].r - wc.r) + std::abs(humans[i].c - wc.c);
                    if (dist < best_dist) { best_dist = dist; best_idx = w; }
                }

                // If my section is done, help with any remaining unbuilt cell
                if (best_idx == -1) {
