                            for (int c = plan.c_min; c <= plan.c_max; c++) {
                                if (passable(r, c)) { target = {r, c}; goto found_corner_target; }
                            }
                        }
                        found_corner_target:;
                    }
                    if (humans[i] != target) actions[i] = move_toward(humans[i], target);
                } else {
                    Point wall_target = my_walls[best_idx];
                    Point stand_pos = {-1, -1};
                    int best_stand_dist = INF;
                    for (int d = 0; d < 4; d++) {
                        int sr = wall_target.r + DR[d], sc = wall_target.c + DC[d];
                        if (!passable(sr, sc)) continue;
                        bool in_safe = is_safe_side_corner(plan, sr, sc);
