# EVOLVE-BLOCK-START
#include <iostream>
#include <vector>
#include <string>
#include <algorithm>
#include <queue>
#include <cmath>
#include <limits>
#include <cstring>

constexpr int GRID_SIZE = 30;
constexpr int NUM_TURNS = 300;
constexpr int INF = std::numeric_limits<int>::max();

struct Point {
    int r, c;
    bool operator==(const Point& o) const { return r == o.r && c == o.c; }
    bool operator!=(const Point& o) const { return !(*this == o); }
};

const int DR[4] = {-1, 1, 0, 0};
const int DC[4] = {0, 0, -1, 1};
const char BUILD_CH[4] = {'u', 'd', 'l', 'r'};
const char MOVE_CH[4] = {'U', 'D', 'L', 'R'};

bool grid[GRID_SIZE + 2][GRID_SIZE + 2];

int N, M;
std::vector<Point> pets;
std::vector<int> pet_types;
std::vector<Point> humans;

bool valid(int r, int c) { return r >= 1 && r <= GRID_SIZE && c >= 1 && c <= GRID_SIZE; }
bool passable(int r, int c) { return valid(r, c) && !grid[r][c]; }

int bfs_dist[GRID_SIZE + 2][GRID_SIZE + 2];
Point bfs_parent[GRID_SIZE + 2][GRID_SIZE + 2];

void compute_bfs_from(Point src) {
    memset(bfs_dist, -1, sizeof(bfs_dist));
    std::queue<Point> q;
    bfs_dist[src.r][src.c] = 0;
    q.push(src);
    while (!q.empty()) {
        Point cur = q.front(); q.pop();
        for (int d = 0; d < 4; d++) {
            int nr = cur.r + DR[d], nc = cur.c + DC[d];
            if (passable(nr, nc) && bfs_dist[nr][nc] == -1) {
                bfs_dist[nr][nc] = bfs_dist[cur.r][cur.c] + 1;
                bfs_parent[nr][nc] = cur;
                q.push({nr, nc});
            }
        }
    }
}

char move_toward(Point from, Point to) {
    if (from == to) return '.';
    compute_bfs_from(from);
    if (bfs_dist[to.r][to.c] == -1) return '.';

    Point cur = to;
    while (!(bfs_parent[cur.r][cur.c] == from)) {
        cur = bfs_parent[cur.r][cur.c];
    }
    for (int d = 0; d < 4; d++) {
        if (from.r + DR[d] == cur.r && from.c + DC[d] == cur.c) {
            return MOVE_CH[d];
        }
    }
    return '.';
}

bool can_build_wall(int r, int c) {
    if (!valid(r, c)) return false;
    if (grid[r][c]) return false;
    for (auto& p : pets) {
        if (p.r == r && p.c == c) return false;
        if (std::abs(p.r - r) + std::abs(p.c - c) == 1) return false;
    }
    for (int i = 0; i < M; i++) {
        if (humans[i].r == r && humans[i].c == c) return false;
    }
    return true;
}

// Enclosure types: strip (1 wall + 3 edges) or L-shape (2 walls + 2 edges)
struct Enclosure {
    int type; // 0=strip, 1=L-shape
    int r_min, r_max, c_min, c_max; // safe zone bounds
    std::vector<Point> wall_cells;
    int area;
    int pets_inside;
    double score;
};

int pet_speed(int type) {
    switch(type) {
        case 1: return 1; // cow
        case 2: return 2; // pig
        case 3: return 3; // rabbit
        case 4: return 2; // dog (1 directed + 1 random)
        case 5: return 2; // cat (1 directed + 1 random)
        default: return 1;
    }
}

double compute_enclosure_score(int area, int pets_inside, int wall_cost,
                                const std::vector<Point>& wall_cells) {
    // Base: area/900 * 2^(-pets_inside)
    double base = (double)area / 900.0 * std::pow(2.0, -(double)pets_inside);

    // Strong bonus for 0 pets
    double pet_mult = (pets_inside == 0) ? 3.0 : (pets_inside == 1) ? 1.0 : 0.2;

    // Construction speed: fewer wall cells = faster = less risk
    double speed_mult = 1.0 / (1.0 + (wall_cost - 30) * 0.02);

    // Pet proximity to wall: penalize if fast pets are near wall cells
    double proximity_penalty = 0.0;
    for (auto& wc : wall_cells) {
        for (int pi = 0; pi < N; pi++) {
            int dist = std::abs(pets[pi].r - wc.r) + std::abs(pets[pi].c - wc.c);
            int speed = pet_speed(pet_types[pi]);
            if (dist <= speed * 3) {
                proximity_penalty += (double)speed / (dist + 1);
            }
        }
    }
    double prox_mult = 1.0 / (1.0 + proximity_penalty * 0.05);

    return base * pet_mult * speed_mult * prox_mult;
}

Enclosure best_enclosure;

void find_best_strip(std::vector<Enclosure>& candidates) {
    for (int edge = 0; edge < 4; edge++) {
        for (int depth = 3; depth <= 14; depth++) {
            Enclosure enc;
            enc.type = 0;

            int wall_pos;
            if (edge == 0) { // top
                wall_pos = depth + 1;
                enc.r_min = 1; enc.r_max = depth;
                enc.c_min = 1; enc.c_max = GRID_SIZE;
            } else if (edge == 1) { // bottom
                wall_pos = GRID_SIZE - depth;
                enc.r_min = GRID_SIZE - depth + 1; enc.r_max = GRID_SIZE;
                enc.c_min = 1; enc.c_max = GRID_SIZE;
            } else if (edge == 2) { // left
                wall_pos = depth + 1;
                enc.r_min = 1; enc.r_max = GRID_SIZE;
                enc.c_min = 1; enc.c_max = depth;
            } else { // right
                wall_pos = GRID_SIZE - depth;
                enc.r_min = 1; enc.r_max = GRID_SIZE;
                enc.c_min = GRID_SIZE - depth + 1; enc.c_max = GRID_SIZE;
            }

            // Generate wall cells
            enc.wall_cells.clear();
            if (edge < 2) {
                for (int c = 1; c <= GRID_SIZE; c++) enc.wall_cells.push_back({wall_pos, c});
            } else {
                for (int r = 1; r <= GRID_SIZE; r++) enc.wall_cells.push_back({r, wall_pos});
            }

            enc.area = (enc.r_max - enc.r_min + 1) * (enc.c_max - enc.c_min + 1);
            enc.pets_inside = 0;
            for (auto& p : pets) {
                if (p.r >= enc.r_min && p.r <= enc.r_max &&
                    p.c >= enc.c_min && p.c <= enc.c_max)
                    enc.pets_inside++;
            }

            enc.score = compute_enclosure_score(enc.area, enc.pets_inside,
                                                 (int)enc.wall_cells.size(), enc.wall_cells);
            candidates.push_back(enc);
        }
    }
}

void find_best_lshape(std::vector<Enclosure>& candidates) {
    // L-shaped corner: use 2 grid edges + 2 built walls
    // Corner 0 (TL): safe zone rows 1..R-1, cols 1..C-1; walls: row R cols 1..C, col C rows 1..R-1
    // Corner 1 (TR): safe zone rows 1..R-1, cols C+1..30; walls: row R cols C..30, col C rows 1..R-1
    // Corner 2 (BL): safe zone rows R+1..30, cols 1..C-1; walls: row R cols 1..C, col C rows R+1..30
    // Corner 3 (BR): safe zone rows R+1..30, cols C+1..30; walls: row R cols C..30, col C rows R+1..30

    for (int corner = 0; corner < 4; corner++) {
        // Try various wall positions
        for (int wr = 4; wr <= 27; wr++) {
            for (int wc = 4; wc <= 27; wc++) {
                Enclosure enc;
                enc.type = 1;
                enc.wall_cells.clear();

                if (corner == 0) {
                    enc.r_min = 1; enc.r_max = wr - 1;
                    enc.c_min = 1; enc.c_max = wc - 1;
                    // Horizontal wall: row wr, cols 1 to wc
                    for (int c = 1; c <= wc; c++) enc.wall_cells.push_back({wr, c});
                    // Vertical wall: col wc, rows 1 to wr-1
                    for (int r = 1; r <= wr - 1; r++) enc.wall_cells.push_back({r, wc});
                } else if (corner == 1) {
                    enc.r_min = 1; enc.r_max = wr - 1;
                    enc.c_min = wc + 1; enc.c_max = GRID_SIZE;
                    // Horizontal wall: row wr, cols wc to 30
                    for (int c = wc; c <= GRID_SIZE; c++) enc.wall_cells.push_back({wr, c});
                    // Vertical wall: col wc, rows 1 to wr-1
                    for (int r = 1; r <= wr - 1; r++) enc.wall_cells.push_back({r, wc});
                } else if (corner == 2) {
                    enc.r_min = wr + 1; enc.r_max = GRID_SIZE;
                    enc.c_min = 1; enc.c_max = wc - 1;
                    // Horizontal wall: row wr, cols 1 to wc
                    for (int c = 1; c <= wc; c++) enc.wall_cells.push_back({wr, c});
                    // Vertical wall: col wc, rows wr+1 to 30
                    for (int r = wr + 1; r <= GRID_SIZE; r++) enc.wall_cells.push_back({r, wc});
                } else {
                    enc.r_min = wr + 1; enc.r_max = GRID_SIZE;
                    enc.c_min = wc + 1; enc.c_max = GRID_SIZE;
                    // Horizontal wall: row wr, cols wc to 30
                    for (int c = wc; c <= GRID_SIZE; c++) enc.wall_cells.push_back({wr, c});
                    // Vertical wall: col wc, rows wr+1 to 30
                    for (int r = wr + 1; r <= GRID_SIZE; r++) enc.wall_cells.push_back({r, wc});
                }

                enc.area = (enc.r_max - enc.r_min + 1) * (enc.c_max - enc.c_min + 1);
                if (enc.area < 80) continue; // too small
                if ((int)enc.wall_cells.size() > 55) continue; // too expensive to build

                enc.pets_inside = 0;
                for (auto& p : pets) {
                    if (p.r >= enc.r_min && p.r <= enc.r_max &&
                        p.c >= enc.c_min && p.c <= enc.c_max)
                        enc.pets_inside++;
                }

                enc.score = compute_enclosure_score(enc.area, enc.pets_inside,
                                                     (int)enc.wall_cells.size(), enc.wall_cells);
                candidates.push_back(enc);
            }
        }
    }
}

void choose_enclosure() {
    std::vector<Enclosure> candidates;
    find_best_strip(candidates);
    find_best_lshape(candidates);

    // Pick the best scoring enclosure
    double best_score = -1;
    int best_idx = 0;
    for (int i = 0; i < (int)candidates.size(); i++) {
        if (candidates[i].score > best_score) {
            best_score = candidates[i].score;
            best_idx = i;
        }
    }
    best_enclosure = candidates[best_idx];
}

bool is_in_safe_zone(int r, int c) {
    return r >= best_enclosure.r_min && r <= best_enclosure.r_max &&
           c >= best_enclosure.c_min && c <= best_enclosure.c_max;
}

// Find the best standing position to build a wall cell (prefer safe side)
Point find_stand_pos(int human_idx, Point wall_cell) {
    Point best = {-1, -1};
    int best_dist = INF;

    for (int d = 0; d < 4; d++) {
        int sr = wall_cell.r + DR[d], sc = wall_cell.c + DC[d];
        if (!passable(sr, sc)) continue;

        bool in_safe = is_in_safe_zone(sr, sc);
        int dist = std::abs(humans[human_idx].r - sr) + std::abs(humans[human_idx].c - sc);
        // Strongly prefer standing on safe side
        int effective_dist = in_safe ? dist : dist + 100;

        if (effective_dist < best_dist) {
            best_dist = effective_dist;
            best = {sr, sc};
        }
    }

    // Fallback: any passable adjacent
    if (best.r == -1) {
        for (int d = 0; d < 4; d++) {
            int sr = wall_cell.r + DR[d], sc = wall_cell.c + DC[d];
            if (passable(sr, sc)) { best = {sr, sc}; break; }
        }
    }
    return best;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::cin >> N;
    pets.resize(N);
    pet_types.resize(N);
    for (int i = 0; i < N; i++) {
        std::cin >> pets[i].r >> pets[i].c >> pet_types[i];
    }

    std::cin >> M;
    humans.resize(M);
    for (int i = 0; i < M; i++) {
        std::cin >> humans[i].r >> humans[i].c;
    }

    memset(grid, false, sizeof(grid));
    choose_enclosure();

    for (int turn = 0; turn < NUM_TURNS; turn++) {
        std::string actions(M, '.');
        std::vector<Point> walls_being_built;
        std::vector<int> cell_claimed(best_enclosure.wall_cells.size(), 0);

        // Dynamic assignment: each human picks nearest unbuilt buildable cell
        // Process humans in order of proximity to unbuilt cells (closest first)
        std::vector<int> human_order(M);
        for (int i = 0; i < M; i++) human_order[i] = i;

        // Sort by minimum distance to any unbuilt wall cell
        std::vector<int> min_dist_to_wall(M, INF);
        for (int i = 0; i < M; i++) {
            for (int w = 0; w < (int)best_enclosure.wall_cells.size(); w++) {
                Point wc = best_enclosure.wall_cells[w];
                if (grid[wc.r][wc.c]) continue;
                int dist = std::abs(humans[i].r - wc.r) + std::abs(humans[i].c - wc.c);
                min_dist_to_wall[i] = std::min(min_dist_to_wall[i], dist);
            }
        }
        std::sort(human_order.begin(), human_order.end(), [&](int a, int b) {
            return min_dist_to_wall[a] < min_dist_to_wall[b];
        });

        for (int hi = 0; hi < M; hi++) {
            int i = human_order[hi];

            // Find nearest unbuilt, unclaimed wall cell
            int best_idx = -1;
            int best_dist = INF;
            for (int w = 0; w < (int)best_enclosure.wall_cells.size(); w++) {
                if (cell_claimed[w]) continue;
                Point wc = best_enclosure.wall_cells[w];
                if (grid[wc.r][wc.c]) continue;

                // Compute distance to the best standing position
                int dist = INF;
                for (int d = 0; d < 4; d++) {
                    int sr = wc.r + DR[d], sc = wc.c + DC[d];
                    if (!passable(sr, sc)) continue;
                    bool in_safe = is_in_safe_zone(sr, sc);
                    int sdist = std::abs(humans[i].r - sr) + std::abs(humans[i].c - sc);
                    int eff = in_safe ? sdist : sdist + 50;
                    dist = std::min(dist, eff);
                }

                if (dist < best_dist) {
                    best_dist = dist;
                    best_idx = w;
                }
            }

            if (best_idx == -1) {
                // All walls built - move into safe zone center
                int tr = (best_enclosure.r_min + best_enclosure.r_max) / 2;
                int tc = (best_enclosure.c_min + best_enclosure.c_max) / 2;
                Point target = {tr, tc};
                if (!passable(target.r, target.c)) {
                    for (int r = best_enclosure.r_min; r <= best_enclosure.r_max; r++) {
                        for (int c = best_enclosure.c_min; c <= best_enclosure.c_max; c++) {
                            if (passable(r, c)) { target = {r, c}; goto found_target; }
                        }
                    }
                    found_target:;
                }
                if (humans[i] != target) {
                    actions[i] = move_toward(humans[i], target);
                }
            } else {
                cell_claimed[best_idx] = 1;
                Point wall_target = best_enclosure.wall_cells[best_idx];
                Point stand_pos = find_stand_pos(i, wall_target);

                if (stand_pos.r == -1) {
                    actions[i] = '.';
                } else if (humans[i] == stand_pos) {
                    // Try to build target cell
                    if (can_build_wall(wall_target.r, wall_target.c)) {
                        for (int d = 0; d < 4; d++) {
                            if (humans[i].r + DR[d] == wall_target.r &&
                                humans[i].c + DC[d] == wall_target.c) {
                                actions[i] = BUILD_CH[d];
                                walls_being_built.push_back(wall_target);
                                break;
                            }
                        }
                    } else {
                        // Target blocked by pet - try ANY adjacent unbuilt buildable cell
                        bool built_alt = false;
                        for (int w = 0; w < (int)best_enclosure.wall_cells.size(); w++) {
                            Point wc2 = best_enclosure.wall_cells[w];
                            if (grid[wc2.r][wc2.c]) continue;
                            if (!can_build_wall(wc2.r, wc2.c)) continue;
                            bool adjacent = false;
                            int build_dir = -1;
                            for (int d = 0; d < 4; d++) {
                                if (humans[i].r + DR[d] == wc2.r && humans[i].c + DC[d] == wc2.c) {
                                    adjacent = true; build_dir = d; break;
                                }
                            }
                            if (adjacent) {
                                bool already_claimed = false;
                                for (auto& wb : walls_being_built) {
                                    if (wb == wc2) { already_claimed = true; break; }
                                }
                                if (!already_claimed) {
                                    actions[i] = BUILD_CH[build_dir];
                                    walls_being_built.push_back(wc2);
                                    built_alt = true;
                                    break;
                                }
                            }
                        }
                        if (!built_alt) actions[i] = '.';
                    }
                } else {
                    // Move toward standing position
                    actions[i] = move_toward(humans[i], stand_pos);
                }
            }
        }

        // Validate moves
        for (int i = 0; i < M; i++) {
            char a = actions[i];
            if (a == 'U' || a == 'D' || a == 'L' || a == 'R') {
                for (int d = 0; d < 4; d++) {
                    if (a == MOVE_CH[d]) {
                        int nr = humans[i].r + DR[d], nc = humans[i].c + DC[d];
                        if (!passable(nr, nc)) { actions[i] = '.'; break; }
                        for (auto& w : walls_being_built) {
                            if (w.r == nr && w.c == nc) { actions[i] = '.'; break; }
                        }
                        break;
                    }
                }
            } else if (a == 'u' || a == 'd' || a == 'l' || a == 'r') {
                for (int d = 0; d < 4; d++) {
                    if (a == BUILD_CH[d]) {
                        int nr = humans[i].r + DR[d], nc = humans[i].c + DC[d];
                        if (!can_build_wall(nr, nc)) actions[i] = '.';
                        break;
                    }
                }
            }
        }

        std::cout << actions << std::endl;

        // Apply actions
        for (int i = 0; i < M; i++) {
            char a = actions[i];
            if (a == 'u' || a == 'd' || a == 'l' || a == 'r') {
                for (int d = 0; d < 4; d++) {
