    // The real metric: area/900 * 2^(-pets_inside) is the per-person satisfaction
    // All M humans share the same zone, so total score ~ M * area/900 * 2^(-pets_inside)
    double satisfaction = (double)area / 900.0 * std::pow(2.0, -(double)pets_inside);

    // Strong bonus for 0 pets (pets can wander in during construction)
    double pet_mult = (pets_inside == 0) ? 2.5 : (pets_inside == 1) ? 0.8 : 0.15;

    // Construction efficiency: turns needed = wall_cost / M (all humans cooperate)
    // But we also need travel time to reach positions
    double turns_to_build = (double)wall_cost / M + 5.0; // +5 for travel
    // Probability of no pet interference decreases with time
    // Penalize slow construction exponentially
    double time_mult = std::exp(-turns_to_build * 0.02);

    // Area efficiency: area per wall cell (higher = better shape)
    double efficiency = (double)area / (double)wall_cost;
    double eff_mult = std::sqrt(efficiency / 8.0); // normalize: strip at depth 8 = 240/30 = 8

    // Pet proximity to wall: high-speed pets near the wall block construction
    double proximity_penalty = 0.0;
    for (auto& wc : wall_cells) {
        for (int pi = 0; pi < N; pi++) {
            int dist = std::abs(pets[pi].r - wc.r) + std::abs(pets[pi].c - wc.c);
            int speed = pet_speed(pet_types[pi]);
            if (dist <= speed * 4) {
                proximity_penalty += (double)speed / (dist + 1);
            }
        }
    }
    double prox_mult = 1.0 / (1.0 + proximity_penalty * 0.03);

    return satisfaction * pet_mult * time_mult * eff_mult * prox_mult;
}

