            return min_dist[a] < min_dist[b];
        });

        for (int hi = 0; hi < M; hi++) {
            int i = human_order[hi];

            // Find nearest unbuilt unclaimed wall cell, preferring cells buildable from safe side
            int best_idx = -1;
            int best_dist_val = INF;
            for (int w = 0; w < (int)best_enclosure.wall_cells.size(); w++) {
                if (cell_claimed[w]) continue;
                Point wc = best_enclosure.wall_cells[w];
                if (grid[wc.r][wc.c]) continue;

                // Distance to best standing position for this cell
                int cell_dist = INF;
                for (int d = 0; d < 4; d++) {
