StripPlan make_strip(int edge, int depth) {
    StripPlan sp;
    sp.edge = edge;
    sp.depth = depth;
    if (edge == 0) {
        sp.wall_pos = depth + 1;
        sp.r_min = 1; sp.r_max = depth; sp.c_min = 1; sp.c_max = GRID_SIZE;
    } else if (edge == 1) {
        sp.wall_pos = GRID_SIZE - depth;
        sp.r_min = GRID_SIZE - depth + 1; sp.r_max = GRID_SIZE; sp.c_min = 1; sp.c_max = GRID_SIZE;
    } else if (edge == 2) {
        sp.wall_pos = depth + 1;
        sp.r_min = 1; sp.r_max = GRID_SIZE; sp.c_min = 1; sp.c_max = depth;
    } else {
        sp.wall_pos = GRID_SIZE - depth;
        sp.r_min = 1; sp.r_max = GRID_SIZE; sp.c_min = GRID_SIZE - depth + 1; sp.c_max = GRID_SIZE;
    }
    sp.area = (sp.r_max - sp.r_min + 1) * (sp.c_max - sp.c_min + 1);
    sp.pets_inside = 0;
    for (auto& p : pets) {
        if (p.r >= sp.r_min && p.r <= sp.r_max && p.c >= sp.c_min && p.c <= sp.c_max)
            sp.pets_inside++;
