}

double score_strip(const StripPlan& sp) {
    double base = (double)sp.area / 900.0 * std::pow(2.0, -(double)sp.pets_inside);
    double pet_mult = (sp.pets_inside == 0) ? 2.5 : (sp.pets_inside == 1) ? 1.0 : 0.3;

    // Pets near wall blocking construction
    auto wall_cells = get_wall_cells(sp.edge, sp.wall_pos);
    double prox_penalty = 0.0;
    for (auto& wc : wall_cells) {
