            int dist = std::abs(pets[pi].r - wc.r) + std::abs(pets[pi].c - wc.c);
            if (dist <= 2) prox_penalty += (double)pet_speed(pet_types[pi]) / (dist + 1);
        }
    }
    double prox_mult = 1.0 / (1.0 + prox_penalty * 0.1);
    double area_mult = std::sqrt((double)sp.area / 150.0);
    return base * pet_mult * prox_mult * area_mult;
}

