int safe_r_min, safe_r_max, safe_c_min, safe_c_max;

bool is_in_safe_zone(int r, int c) {
    return r >= safe_r_min && r <= safe_r_max && c >= safe_c_min && c <= safe_c_max;
}

void choose_plans() {
    // Phase 1: find a shallow pet-free strip (depth 3-5)
    StripPlan best_p1;
    best_p1.score = -1;

    for (int edge = 0; edge < 4; edge++) {
        for (int depth = 3; depth <= 5; depth++) {
            StripPlan sp = make_strip(edge, depth);
            if (sp.pets_inside > 0) continue; // Phase 1 MUST be pet-free
            sp.score = score_strip(sp);
            if (sp.score > best_p1.score) best_p1 = sp;
        }
    }

    // If no pet-free shallow strip exists, allow depth up to 8 with 0 pets
    if (best_p1.score < 0) {
        for (int edge = 0; edge < 4; edge++) {
            for (int depth = 3; depth <= 8; depth++) {
                StripPlan sp = make_strip(edge, depth);
                if (sp.pets_inside > 0) continue;
                sp.score = score_strip(sp);
                if (sp.score > best_p1.score) best_p1 = sp;
            }
        }
    }

    // Absolute fallback: best strip regardless of pets
    if (best_p1.score < 0) {
        for (int edge = 0; edge < 4; edge++) {
            for (int depth = 3; depth <= 14; depth++) {
                StripPlan sp = make_strip(edge, depth);
                sp.score = score_strip(sp);
                if (sp.score > best_p1.score) best_p1 = sp;
            }
        }
    }

    phase1_plan = best_p1;
    chosen_edge = best_p1.edge;

    // Phase 2: expand deeper on the SAME edge
    // The phase 2 wall goes deeper into the grid
    StripPlan best_p2;
    best_p2.score = -1;

    for (int depth = phase1_plan.depth + 2; depth <= 14; depth++) {
        StripPlan sp = make_strip(chosen_edge, depth);
        // For phase 2, the "safe zone" is between phase 1 wall and phase 2 wall
        // But actually the full safe zone after phase 2 is the entire depth strip
        // Phase 2 just needs to be buildable from the phase 1 safe zone side
        sp.score = score_strip(sp);
        if (sp.score > best_p2.score) best_p2 = sp;
    }

    phase2_plan = best_p2;

    // Also consider: single deep strip (no phase splitting) if it's clearly better
    StripPlan best_single;
    best_single.score = -1;
    for (int edge = 0; edge < 4; edge++) {
        for (int depth = 3; depth <= 14; depth++) {
            StripPlan sp = make_strip(edge, depth);
            sp.score = score_strip(sp);
            if (sp.score > best_single.score) best_single = sp;
        }
    }

    // If best single strip scores better than phase2, and best_single edge == chosen_edge
    // with depth > phase1_depth, use two-phase. Otherwise just use best_single as a
    // single-phase approach.
    if (best_single.edge == chosen_edge && best_single.depth > phase1_plan.depth &&
        best_single.pets_inside <= 1) {
        // Two-phase makes sense: phase2 expands to the deeper strip
        phase2_plan = best_single;
    } else if (best_single.score > phase1_plan.score * 1.5) {
        // Single deep strip is much better - use it as phase1 only (skip phase2)
        phase1_plan = best_single;
        chosen_edge = best_single.edge;
        phase2_plan.score = -1; // no phase 2
    }

    // Set up initial wall cells and safe zone for phase 1
    phase = 0;
    current_wall_cells = get_wall_cells(phase1_plan.edge, phase1_plan.wall_pos);
    safe_r_min = phase1_plan.r_min; safe_r_max = phase1_plan.r_max;
    safe_c_min = phase1_plan.c_min; safe_c_max = phase1_plan.c_max;
}

bool wall_complete() {
    for (auto& wc : current_wall_cells) {
        if (!grid[wc.r][wc.c]) return false;
    }
    return true;
}

void transition_to_phase2() {
    if (phase2_plan.score <= 0) {
        phase = 2; // done
        return;
    }

    // Check if any pets are in the expanded zone
    int pets_in_expansion = 0;
    for (auto& p : pets) {
        if (p.r >= phase2_plan.r_min && p.r <= phase2_plan.r_max &&
            p.c >= phase2_plan.c_min && p.c <= phase2_plan.c_max) {
            // Is this pet in the expansion area (between phase1 wall and phase2 wall)?
            if (!is_in_safe_zone(p.r, p.c)) {
                pets_in_expansion++;
            }
        }
    }

    // Only expand if few pets in expansion zone
    if (pets_in_expansion > 2) {
        phase = 2; // skip phase 2
        return;
    }

    phase = 1;
    current_wall_cells = get_wall_cells(phase2_plan.edge, phase2_plan.wall_pos);
    safe_r_min = phase2_plan.r_min; safe_r_max = phase2_plan.r_max;
    safe_c_min = phase2_plan.c_min; safe_c_max = phase2_plan.c_max;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::cin >> N;
    pets.resize(N);
    pet_types.resize(N);
    for (int i = 0; i < N; i++) {
        std::cin >> pets[i].r >> pets[i].c >> pet_types[i];
    }

    std::cin >> M;
    humans.resize(M);
    for (int i = 0; i < M; i++) {
        std::cin >> humans[i].r >> humans[i].c;
    }

    memset(grid, false, sizeof(grid));
    choose_plans();

    for (int turn = 0; turn < NUM_TURNS; turn++) {
        // Check phase transitions
        if (phase < 2 && wall_complete()) {
            if (phase == 0) {
                transition_to_phase2();
            } else {
                phase = 2;
                // Update safe zone to phase2
                safe_r_min = phase2_plan.r_min; safe_r_max = phase2_plan.r_max;
                safe_c_min = phase2_plan.c_min; safe_c_max = phase2_plan.c_max;
            }
        }

        std::string actions(M, '.');
        std::vector<Point> walls_being_built;

        if (phase < 2) {
            // Building phase: dynamic assignment
            std::vector<bool> cell_claimed(current_wall_cells.size(), false);

            // Sort humans by proximity to nearest unbuilt wall cell
            std::vector<int> human_order(M);
            for (int i = 0; i < M; i++) human_order[i] = i;

            std::vector<int> min_d(M, INF);
            for (int i = 0; i < M; i++) {
                for (int w = 0; w < (int)current_wall_cells.size(); w++) {
                    Point wc = current_wall_cells[w];
                    if (grid[wc.r][wc.c]) continue;
                    int dist = std::abs(humans[i].r - wc.r) + std::abs(humans[i].c - wc.c);
                    min_d[i] = std::min(min_d[i], dist);
                }
            }
            std::sort(human_order.begin(), human_order.end(), [&](int a, int b) {
                return min_d[a] < min_d[b];
            });

            for (int hi = 0; hi < M; hi++) {
                int i = human_order[hi];

                // Find nearest unbuilt, unclaimed wall cell
                int best_idx = -1;
                int best_dist_val = INF;
                for (int w = 0; w < (int)current_wall_cells.size(); w++) {
                    if (cell_claimed[w]) continue;
                    Point wc = current_wall_cells[w];
                    if (grid[wc.r][wc.c]) continue;

                    // Distance to best standing position
                    int cell_dist = INF;
                    for (int d = 0; d < 4; d++) {
                        int sr = wc.r + DR[d], sc = wc.c + DC[d];
                        if (!passable(sr, sc)) continue;
                        bool in_safe = is_in_safe_zone(sr, sc);
                        int sdist = std::abs(humans[i].r - sr) + std::abs(humans[i].c - sc);
                        int eff = in_safe ? sdist : sdist + 50;
                        cell_dist = std::min(cell_dist, eff);
                    }

                    if (cell_dist < best_dist_val) {
                        best_dist_val = cell_dist;
                        best_idx = w;
                    }
                }

                if (best_idx == -1) {
                    // All cells assigned or built - move to safe zone center
                    int tr = (safe_r_min + safe_r_max) / 2;
                    int tc = (safe_c_min + safe_c_max) / 2;
                    Point target = {tr, tc};
                    if (!passable(target.r, target.c)) {
                        for (int r = safe_r_min; r <= safe_r_max; r++) {
                            for (int c = safe_c_min; c <= safe_c_max; c++) {
                                if (passable(r, c)) { target = {r, c}; goto found_target; }
                            }
                        }
                        found_target:;
                    }
                    if (humans[i] != target) actions[i] = move_toward(humans[i], target);
                } else {
                    cell_claimed[best_idx] = true;
                    Point wall_target = current_wall_cells[best_idx];

                    // Find standing position (prefer safe side)
                    Point stand_pos = {-1, -1};
                    int best_stand_dist = INF;
                    for (int d = 0; d < 4; d++) {
                        int sr = wall_target.r + DR[d], sc = wall_target.c + DC[d];
                        if (!passable(sr, sc)) continue;
                        bool in_safe = is_in_safe_zone(sr, sc);
                        int dist = std::abs(humans[i].r - sr) + std::abs(humans[i].c - sc);
                        int eff = in_safe ? dist : dist + 100;
                        if (eff < best_stand_dist) {
                            best_stand_dist = eff;
                            stand_pos = {sr, sc};
                        }
                    }
                    if (stand_pos.r == -1) {
                        for (int d = 0; d < 4; d++) {
                            int sr = wall_target.r + DR[d], sc = wall_target.c + DC[d];
                            if (passable(sr, sc)) { stand_pos = {sr, sc}; break; }
                        }
                    }

                    if (stand_pos.r == -1) {
                        actions[i] = '.';
                    } else if (humans[i] == stand_pos) {
                        if (can_build_wall(wall_target.r, wall_target.c)) {
                            for (int d = 0; d < 4; d++) {
                                if (humans[i].r + DR[d] == wall_target.r &&
                                    humans[i].c + DC[d] == wall_target.c) {
                                    actions[i] = BUILD_CH[d];
                                    walls_being_built.push_back(wall_target);
                                    break;
                                }
                            }
                        } else {
                            // Pet blocking - try any adjacent buildable wall cell
                            bool built_alt = false;
                            for (int w = 0; w < (int)current_wall_cells.size(); w++) {
                                Point wc2 = current_wall_cells[w];
                                if (grid[wc2.r][wc2.c]) continue;
                                if (!can_build_wall(wc2.r, wc2.c)) continue;
                                bool adjacent = false;
                                int build_dir = -1;
                                for (int d = 0; d < 4; d++) {
                                    if (humans[i].r + DR[d] == wc2.r && humans[i].c + DC[d] == wc2.c) {
                                        adjacent = true; build_dir = d; break;
                                    }
                                }
                                if (adjacent) {
                                    bool already = false;
                                    for (auto& wb : walls_being_built) {
                                        if (wb == wc2) { already = true; break; }
                                    }
                                    if (!already) {
                                        actions[i] = BUILD_CH[build_dir];
                                        walls_being_built.push_back(wc2);
                                        built_alt = true;
                                        break;
                                    }
                                }
                            }
                            if (!built_alt) actions[i] = '.';
                        }
                    } else {
                        actions[i] = move_toward(humans[i], stand_pos);
                    }
                }
            }
        } else {
            // Phase 2 done: all humans move to safe zone center
            for (int i = 0; i < M; i++) {
                int tr = (safe_r_min + safe_r_max) / 2;
                int tc = (safe_c_min + safe_c_max) / 2;
                Point target = {tr, tc};
                if (!passable(target.r, target.c)) {
                    for (int r = safe_r_min; r <= safe_r_max; r++) {
                        for (int c = safe_c_min; c <= safe_c_max; c++) {
                            if (passable(r, c)) { target = {r, c}; goto found2; }
                        }
                    }
                    found2:;
                }
                if (humans[i] != target) actions[i] = move_toward(humans[i], target);
            }
        }

        // Validate moves
        for (int i = 0; i < M; i++) {
            char a = actions[i];
            if (a == 'U' || a == 'D' || a == 'L' || a == 'R') {
                for (int d = 0; d < 4; d++) {
                    if (a == MOVE_CH[d]) {
                        int nr = humans[i].r + DR[d], nc = humans[i].c + DC[d];
                        if (!passable(nr, nc)) { actions[i] = '.'; break; }
                        for (auto& w : walls_being_built) {
                            if (w.r == nr && w.c == nc) { actions[i] = '.'; break; }
                        }
                        break;
                    }
                }
            } else if (a == 'u' || a == 'd' || a == 'l' || a == 'r') {
                for (int d = 0; d < 4; d++) {
                    if (a == BUILD_CH[d]) {
                        int nr = humans[i].r + DR[d], nc = humans[i].c + DC[d];
                        if (!can_build_wall(nr, nc)) actions[i] = '.';
                        break;
                    }
                }
            }
        }

        std::cout << actions << std::endl;

        // Apply actions
        for (int i = 0; i < M; i++) {
            char a = actions[i];
            if (a == 'u' || a == 'd' || a == 'l' || a == 'r') {
                for (int d = 0; d < 4; d++) {
                    if (a == BUILD_CH[d]) {
                        int nr = humans[i].r + DR[d], nc = humans[i].c + DC[d];
                        if (valid(nr, nc)) grid[nr][nc] = true;
                        break;
                    }
                }
            } else if (a == 'U' || a == 'D' || a == 'L' || a == 'R') {
                for (int d = 0; d < 4; d++) {
                    if (a == MOVE_CH[d]) {
                        int nr = humans[i].r + DR[d], nc = humans[i].c + DC[d];
                        if (passable(nr, nc)) humans[i] = {nr, nc};
                        break;
                    }
                }
            }
        }

        // Read pet movements
        for (int i = 0; i < N; i++) {
            std::string pet_move;
            std::cin >> pet_move;
            if (pet_move == ".") continue;
            for (char ch : pet_move) {
                for (int d = 0; d < 4; d++) {
                    if (ch == MOVE_CH[d]) {
                        pets[i].r += DR[d];
                        pets[i].c += DC[d];
                        break;
                    }
                }
            }
        }
    }

    return 0;
}
