# EVOLVE-BLOCK-START
#include <iostream>
#include <vector>
#include <string>
#include <algorithm>
#include <queue>
#include <cmath>
#include <limits>
#include <cstring>

constexpr int GRID_SIZE = 30;
constexpr int NUM_TURNS = 300;
constexpr int INF = std::numeric_limits<int>::max();

struct Point {
    int r, c;
    bool operator==(const Point& o) const { return r == o.r && c == o.c; }
    bool operator!=(const Point& o) const { return !(*this == o); }
};

const int DR[4] = {-1, 1, 0, 0};
const int DC[4] = {0, 0, -1, 1};
const char BUILD_CH[4] = {'u', 'd', 'l', 'r'};
const char MOVE_CH[4] = {'U', 'D', 'L', 'R'};

bool grid[GRID_SIZE + 2][GRID_SIZE + 2];

int N, M;
std::vector<Point> pets;
std::vector<int> pet_types;
std::vector<Point> humans;

bool valid(int r, int c) { return r >= 1 && r <= GRID_SIZE && c >= 1 && c <= GRID_SIZE; }
bool passable(int r, int c) { return valid(r, c) && !grid[r][c]; }

int bfs_dist[GRID_SIZE + 2][GRID_SIZE + 2];
Point bfs_parent[GRID_SIZE + 2][GRID_SIZE + 2];

void compute_bfs_from(Point src) {
    memset(bfs_dist, -1, sizeof(bfs_dist));
    std::queue<Point> q;
    bfs_dist[src.r][src.c] = 0;
    q.push(src);
    while (!q.empty()) {
        Point cur = q.front(); q.pop();
        for (int d = 0; d < 4; d++) {
            int nr = cur.r + DR[d], nc = cur.c + DC[d];
            if (passable(nr, nc) && bfs_dist[nr][nc] == -1) {
                bfs_dist[nr][nc] = bfs_dist[cur.r][cur.c] + 1;
                bfs_parent[nr][nc] = cur;
                q.push({nr, nc});
            }
        }
    }
}

char move_toward(Point from, Point to) {
    if (from == to) return '.';
    compute_bfs_from(from);
    if (bfs_dist[to.r][to.c] == -1) return '.';

    Point cur = to;
    while (!(bfs_parent[cur.r][cur.c] == from)) {
        cur = bfs_parent[cur.r][cur.c];
    }
    for (int d = 0; d < 4; d++) {
        if (from.r + DR[d] == cur.r && from.c + DC[d] == cur.c) {
            return MOVE_CH[d];
        }
    }
    return '.';
}

bool can_build_wall(int r, int c) {
    if (!valid(r, c)) return false;
    if (grid[r][c]) return false;
    for (auto& p : pets) {
        if (p.r == r && p.c == c) return false;
        if (std::abs(p.r - r) + std::abs(p.c - c) == 1) return false;
    }
    for (int i = 0; i < M; i++) {
        if (humans[i].r == r && humans[i].c == c) return false;
    }
    return true;
}

int pet_speed(int type) {
    switch(type) {
        case 1: return 1;
        case 2: return 2;
        case 3: return 3;
        case 4: return 2;
        case 5: return 2;
        default: return 1;
    }
}

// === Strategy: concentrated strip with greedy dynamic cell assignment ===
// Same strip selection as parent but with smarter construction logic:
// - Each turn, greedily assign humans to wall cells using min-cost matching
// - Humans prefer building from the safe side
// - When blocked, humans opportunistically build any adjacent wall cell

struct StripPlan {
    int edge;
    int depth;
    int wall_pos;
    int r_min, r_max, c_min, c_max;
    int area;
    int pets_inside;
    double score;
};

StripPlan best_strip;
std::vector<Point> wall_cells;

StripPlan make_strip(int edge, int depth) {
    StripPlan sp;
    sp.edge = edge;
    sp.depth = depth;
    if (edge == 0) {
        sp.wall_pos = depth + 1;
        sp.r_min = 1; sp.r_max = depth; sp.c_min = 1; sp.c_max = GRID_SIZE;
    } else if (edge == 1) {
        sp.wall_pos = GRID_SIZE - depth;
        sp.r_min = GRID_SIZE - depth + 1; sp.r_max = GRID_SIZE; sp.c_min = 1; sp.c_max = GRID_SIZE;
    } else if (edge == 2) {
        sp.wall_pos = depth + 1;
        sp.r_min = 1; sp.r_max = GRID_SIZE; sp.c_min = 1; sp.c_max = depth;
    } else {
        sp.wall_pos = GRID_SIZE - depth;
        sp.r_min = 1; sp.r_max = GRID_SIZE; sp.c_min = GRID_SIZE - depth + 1; sp.c_max = GRID_SIZE;
    }
    sp.area = (sp.r_max - sp.r_min + 1) * (sp.c_max - sp.c_min + 1);
    sp.pets_inside = 0;
    for (auto& p : pets) {
        if (p.r >= sp.r_min && p.r <= sp.r_max && p.c >= sp.c_min && p.c <= sp.c_max)
            sp.pets_inside++;
    }
    return sp;
}

void choose_strip() {
    best_strip.score = -1;

    for (int edge = 0; edge < 4; edge++) {
        for (int depth = 3; depth <= 14; depth++) {
            StripPlan sp = make_strip(edge, depth);

            double base = (double)sp.area / 900.0 * std::pow(2.0, -(double)sp.pets_inside);
            double pet_mult = (sp.pets_inside == 0) ? 2.5 : (sp.pets_inside == 1) ? 1.0 : 0.3;

            // Pets near wall
            double prox_penalty = 0.0;
            if (edge < 2) {
                for (int pi = 0; pi < N; pi++) {
                    if (std::abs(pets[pi].r - (sp.wall_pos)) <= 1)
                        prox_penalty += pet_speed(pet_types[pi]);
                }
            } else {
                for (int pi = 0; pi < N; pi++) {
                    if (std::abs(pets[pi].c - (sp.wall_pos)) <= 1)
                        prox_penalty += pet_speed(pet_types[pi]);
                }
            }
            double prox_mult = 1.0 / (1.0 + prox_penalty * 0.3);
            double area_mult = std::sqrt((double)sp.area / 150.0);

            sp.score = base * pet_mult * prox_mult * area_mult;
            if (sp.score > best_strip.score) best_strip = sp;
        }
    }

    // Generate wall cells
    wall_cells.clear();
    if (best_strip.edge < 2) {
        for (int c = 1; c <= GRID_SIZE; c++) wall_cells.push_back({best_strip.wall_pos, c});
    } else {
        for (int r = 1; r <= GRID_SIZE; r++) wall_cells.push_back({r, best_strip.wall_pos});
    }
}

bool is_in_safe_zone(int r, int c) {
    return r >= best_strip.r_min && r <= best_strip.r_max &&
           c >= best_strip.c_min && c <= best_strip.c_max;
}

// Greedy matching: assign each human to the wall cell that minimizes their total "cost"
// Cost = distance to best standing position (safe-side preferred)
int compute_cell_cost(int human_idx, int wall_idx) {
    Point wc = wall_cells[wall_idx];
    if (grid[wc.r][wc.c]) return INF;

    int best_cost = INF;
    for (int d = 0; d < 4; d++) {
        int sr = wc.r + DR[d], sc = wc.c + DC[d];
        if (!passable(sr, sc)) continue;
        bool in_safe = is_in_safe_zone(sr, sc);
        int dist = std::abs(humans[human_idx].r - sr) + std::abs(humans[human_idx].c - sc);
        int eff = in_safe ? dist : dist + 50;
